 1	import type { ChangeEvent, FC } from 'react';
 2	import { useModal } from 'src/modules/Providers/modals/ModalHOC/useModal';
 3	import { useForkliftTranslation } from 'src/utils/i18n';
 4	
 5	import {
 6	  Button,
 7	  ButtonVariant,
 8	  FileUpload,
 9	  type FileUploadProps,
10	  Flex,
11	  FlexItem,
12	} from '@patternfly/react-core';
13	
14	import FetchCertificateModal from './FetchCertificateModal';
15	
16	import './CertificateUpload.style.scss';
17	
18	type CertificateUploadBaseProps = Omit<FileUploadProps, 'validated'>;
19	
20	type CertificateUploadProps = {
21	  url?: string;
22	  validated?: 'success' | 'error' | 'default' | 'warning';
23	} & CertificateUploadBaseProps;
24	
25	/**
26	 * Provide the certificate using following paths:
27	 * 1. manual copy-paste (provided by FileUpload widget)
28	 * 2. uploading a file (provided by FileUpload widget)
29	 * 3. fetch from the specified URL (via tls-certificate endpoint) end verify
30	 */
31	const CertificateUpload: FC<CertificateUploadProps> = ({
32	  browseButtonText,
33	  filenamePlaceholder,
34	  id,
35	  isDisabled,
36	  onClearClick,
37	  onDataChange,
38	  onTextChange,
39	  type,
40	  url,
41	  validated,
42	  value,
43	}) => {
44	  const { showModal } = useModal();
45	  const { t } = useForkliftTranslation();
46	  const isText = !type || type === 'text';
47	  const onClick = () => {
48	    const syntheticEvent = {
49	      target: { value },
50	    } as ChangeEvent<HTMLTextAreaElement>;
51	
52	    showModal(
53	      <FetchCertificateModal
54	        url={url ?? ''}
55	        handleSave={(saved) => {
56	          onTextChange?.(syntheticEvent, saved);
57	        }}
58	        existingCert={(value as string) ?? ''}
59	      />,
60	    );
61	  };
62	
63	  return (
64	    <FileUpload
65	      id={id}
66	      type={type ?? 'text'}
67	      filenamePlaceholder={filenamePlaceholder ?? t('Drag and drop a file or upload one')}
68	      value={value}
69	      validated={validated}
70	      onDataChange={onDataChange}
71	      onTextChange={onTextChange}
72	      onClearClick={onClearClick}
73	      browseButtonText={browseButtonText ?? t('Upload')}
74	      isDisabled={isDisabled}
75	    >
76	      {url && isText && (
77	        <Flex>
78	          <FlexItem>
79	            <Button
80	              className="forklift-certificate-upload-margin"
81	              isDisabled={isDisabled ?? !url?.trim().startsWith('https://')}
82	              variant={ButtonVariant.secondary}
83	              onClick={onClick}
84	            >
85	              {t('Fetch certificate from URL')}
86	            </Button>
87	          </FlexItem>
88	        </Flex>
89	      )}
90	    </FileUpload>
91	  );
92	};
93	
94	export default CertificateUpload;

